#include <cstdint>

// Some C++ standard libraries (notably the OpenHarmony / OHOS toolchain) do not
// ship <source_location> at all. When it is available we simply alias it; when
// it is not, we provide a stand-in that mirrors enough of its surface for
// diagnostic call sites.
