// Adding a new type to `namespace std` is undefined behaviour (C++20
// [namespace.constraints]/5), so we deliberately do NOT do that here.

#if defined(__has_include) && __has_include(<source_location>) && \
    defined(__cpp_lib_source_location) && __cpp_lib_source_location >= 201907L
#include <source_location>
#define MLN_HAVE_STD_SOURCE_LOCATION 1
#else
#define MLN_HAVE_STD_SOURCE_LOCATION 0
#endif

