#define MLN_SRCLOC_FILE() __builtin_FILE()
#else
#define MLN_SRCLOC_FILE() __FILE__
#endif
#if defined(__has_builtin) && __has_builtin(__builtin_FUNCTION)
#define MLN_SRCLOC_FUNCTION() __builtin_FUNCTION()
#else
#define MLN_SRCLOC_FUNCTION() ""
#endif
#if defined(__has_builtin) && __has_builtin(__builtin_LINE)
#define MLN_SRCLOC_LINE() __builtin_LINE()
#else
#define MLN_SRCLOC_LINE() __LINE__
#endif
#if defined(__has_builtin) && __has_builtin(__builtin_COLUMN)
#define MLN_SRCLOC_COLUMN() __builtin_COLUMN()
#else
#define MLN_SRCLOC_COLUMN() 0u
