cat > /tmp/opencode/srcloc_test_fallback.cpp <<'EOF'
// Pretend <source_location> is unavailable, as on OpenHarmony's toolchain.
#include <mbgl/util/source_location.hpp>

#if MLN_HAVE_STD_SOURCE_LOCATION
#error "FALLBACK TEST: expected MLN_HAVE_STD_SOURCE_LOCATION == 0"
#endif
static_assert(!__is_same(mbgl::util::source_location, std::source_location), "fallback should define its own type");

#include <cstdio>
static mbgl::util::source_location captured() {
    return mbgl::util::source_location::current();
}
int main() {
    auto loc = captured();
    std::printf("FALLBACK file=%s func=%s line=%u col=%u\n",
                loc.file_name(), loc.function_name(), loc.line(), loc.column());
    return int(loc.line()) == 0 ? 1 : 0;
}
EOF
# Simulate OpenHarmony by blocking access to <source_location> via -isystem exclusion trick:
# We pass -nostdinc++ won't work (loses all std). Instead, redirect <source_location> to empty via -include.
# Simplest robust approach: a wrapper that predefines __cpp_lib_source_location away and uses a fake cstdint-only env.
# We'll just compile with a macro that forces the fallback by not finding the header:
mkdir -p /tmp/opencode/fakestd
# Create an empty <source_location> so __has_include reports true but it provides nothing,
# AND undef the feature macro so the fallback branch is taken. We achieve the "no header" case
# by adding -D__cpp_lib_source_location=0 ... but the check is `>= 201907L`. Override via -U won't
# work for predefined macros under g++. So instead we point -isystem at fakestd which has NO
# source_location, and -nostdinc++ to drop libstdc++, then add back /usr/include/c++/... minus it.
# Cleaner: use a grep-confirmed manual approach: compile with -isystem that excludes the real header
# by creating a shadow header that triggers __has_include to be false. Easiest: use clang++ -nostdinc++
# plus provide our own minimal cstdint.
echo "g++ approach:" 
g++ -std=c++20 -nostdinc++ -I/app/include -isystem /tmp/opencode/fakestd -Wall -Wextra -Werror -include cstdint /tmp/opencode/srcloc_test_fallback.cpp -o /tmp/opencode/srcloc_test_fb 2>&1 | head -5 || echo "(need cstdint; providing minimal)"
ls /tmp/opencode/fakestd

